// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/Strings.sol";

// =========================================================================
// STRUCT GLOBAL
// Ditempatkan di sini agar otomatis terbawa saat file ini di-import
// =========================================================================
struct PlayerData {
    string nickname; 
    string lane;
    uint64 games;
    uint64 kills;
    uint64 deaths;
    uint64 assists;
}

// =============================================================================
// PlayerCardRenderer.sol (Versi Modular Terpisah)
// =============================================================================
contract PlayerCardRenderer {
    using Strings for uint256;

    function getBackgroundLayer() public pure returns (string memory) {
        return string.concat(
            '<rect x="0" y="0" width="320" height="400" fill="#0b101e"/>',
            '<rect x="8" y="8" width="304" height="384" fill="#141e33"/>',
